/-- `Y=Y(A)` almost surely, written as zero mass on inconsistent atoms. -/
def Consistency {d : ℕ} (Q : PotentialLaw d) : Prop :=
  ∀ z, z.2.2.1 ≠ (if z.2.1 then z.2.2.2.2 else z.2.2.2.1) → fullMass Q z = 0

