/-- The nonnegative four-cell cone with treatment mass in the overlap band. -/
def overlapCone (epsilon : ℝ) : Set (Cell → ℝ) :=
  {u | (∀ i, 0 ≤ u i) ∧
    epsilon * vectorMass u ≤ vectorArmMass u 1 ∧
    vectorArmMass u 1 ≤ (1 - epsilon) * vectorMass u}
